codeExample1.code:
#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n = 5;
    // Allocate memory on the heap for 5 integers
    int *arr = malloc(n * sizeof(*arr));

    // Always check if the allocation succeeded
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed!\n");
        return 1;
    }

    // Safe to populate and use
    for (int i = 0; i < n; i++) {
        arr[i] = (i + 1) * 10;
    }

    // Print the dynamic array
    for (int i = 0; i < n; i++) {
        printf("arr[%d] = %d\n", i, arr[i]);
    }

    // Explicitly release the memory back to the operating system
    free(arr);

    // Prevent dangling pointer use
    arr = NULL;

    return 0;
}

codeExample2.code:
#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int num_elements = 3;

    // calloc allocates AND zero-initializes elements
    int *arr = calloc(num_elements, sizeof(*arr));
    if (arr == NULL) {
        return 1;
    }

    printf("Initial zeros:\n");
    for (int i = 0; i < num_elements; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    // Resize dynamic array to hold 6 elements
    int new_elements = 6;
    int *temp = realloc(arr, new_elements * sizeof(*temp));
    if (temp == NULL) {
        // realloc failed, but arr is still valid and needs to be freed
        free(arr);
        return 1;
    }

    // realloc was successful, safe to overwrite arr
    arr = temp;

    // Initialize the newly added elements
    for (int i = num_elements; i < new_elements; i++) {
        arr[i] = (i + 1) * 100;
    }

    printf("Resized array:\n");
    for (int i = 0; i < new_elements; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    free(arr);
    return 0;
}

