int **allocate_matrix(int rows, int cols) {
    int **matrix = malloc(rows * sizeof(*matrix));
    if (!matrix) return NULL;
    for (int i = 0; i < rows; i++) {
        matrix[i] = malloc(cols * sizeof(**matrix));
        if (!matrix[i]) {
            // Rollback already allocated rows to prevent leaks
            for (int j = 0; j < i; j++) free(matrix[j]);
            free(matrix);
            return NULL;
        }
    }
    return matrix;
}

void *safe_double_capacity(void *ptr, size_t current_size) {
    if (current_size == 0) return NULL;
    size_t new_size = current_size * 2;
    void *temp = realloc(ptr, new_size);
    if (temp == NULL) {
        // Original memory is intact! Log error but do not lose ptr.
        fprintf(stderr, "Critical: Resizing failed. Original memory preserved.\n");
        return NULL;
    }
    return temp;
}

questionsAndAnswers.question:
Identify and fix the memory leak in the following function:
void process_data(void) {
    int *data = malloc(100 * sizeof(int));
    if (data == NULL) return;
    // processing logic...
    if (error_condition) return;
    free(data);
}

questionsAndAnswers.answer:
The leak occurs on early returns inside the error handling branch. If 'error_condition' is true, the function returns immediately without invoking 'free(data)'. To fix it, you must free memory before returning, or restructure the exits:
void process_data(void) {
    int *data = malloc(100 * sizeof(int));
    if (data == NULL) return;
    // processing logic...
    if (error_condition) {
        free(data); // Fix: Free memory before escaping function
        return;
    }
    free(data);
}

char *create_string_clone(const char *src) {
    if (src == NULL) return NULL;
    size_t len = strlen(src);
    // Allocate len + 1 bytes to make room for null-terminator
    char *dest = malloc((len + 1) * sizeof(*dest));
    if (dest == NULL) return NULL;
    strcpy(dest, src);
    return dest;
}

typedef struct {
    int *data;
    size_t size;
    size_t capacity;
} IntVector;

IntVector* create_vector(size_t initial_cap) {
    IntVector *vec = malloc(sizeof(*vec));
    if (!vec) return NULL;
    vec->data = malloc(initial_cap * sizeof(*(vec->data)));
    if (!vec->data) {
        free(vec);
        return NULL;
    }
    vec->size = 0;
    vec->capacity = initial_cap;
    return vec;
}

int append_vector(IntVector *vec, int val) {
    if (vec->size >= vec->capacity) {
        size_t new_cap = vec->capacity * 2;
        int *temp = realloc(vec->data, new_cap * sizeof(*temp));
        if (!temp) return 0; // Failed to resize
        vec->data = temp;
        vec->capacity = new_cap;
    }
    vec->data[vec->size++] = val;
    return 1; // Success
}

void destroy_vector(IntVector *vec) {
    if (vec) {
        free(vec->data);
        free(vec);
    }
}

